+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fr'; weight: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | 'fr'; weight: number};
+
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const trackPattern = /minmax\\([^)]*\\)|\\S+/g;
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) {
+		return [];
+	}
+
+	return (template.match(trackPattern) ?? []).map(token => {
+		if (token === 'auto') {
+			return {type: 'auto'};
+		}
+
+		const fractional = /^(\\d*\\.?\\d+)fr$/.exec(token);
+		if (fractional) {
+			return {type: 'fr', weight: Number(fractional[1])};
+		}
+
+		const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(fr)?\\s*\\)$/.exec(
+			token,
+		);
+		if (minmax) {
+			return {
+				type: 'minmax',
+				min: Number(minmax[1]),
+				max: minmax[3] ? 'fr' : Number(minmax[2]),
+				weight: minmax[3] ? Number(minmax[2]) : 0,
+			};
+		}
+
+		const size = Number(token);
+		if (Number.isFinite(size) && size >= 0) {
+			return {type: 'fixed', size};
+		}
+
+		throw new Error(`Invalid grid track size: ${token}`);
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') {
+		return [value, value + 1];
+	}
+
+	if (!value) {
+		return undefined;
+	}
+
+	const [start, end] = value.split('/').map(part => Number(part.trim()));
+	if (!Number.isInteger(start) || start < 1 || (end !== undefined && (!Number.isInteger(end) || end <= start))) {
+		throw new Error(`Invalid grid placement: ${value}`);
+	}
+
+	return [start, end ?? start + 1];
+};
+
+const getGap = (node: DOMElement, gutter: typeof Yoga.GUTTER_COLUMN | typeof Yoga.GUTTER_ROW): number =>
+	node.yogaNode!.getGap(gutter).value;
+
+const gridChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+
+const resetGridItems = (node: DOMNode): void => {
+	if (node.nodeName === '#text') {
+		return;
+	}
+
+	for (const child of gridChildren(node)) {
+		if (node.style.display === 'grid') {
+			child.yogaNode!.setPositionType(
+				child.style.position === 'absolute'
+					? Yoga.POSITION_TYPE_ABSOLUTE
+					: Yoga.POSITION_TYPE_RELATIVE,
+			);
+			child.yogaNode!.setWidthAuto();
+			child.yogaNode!.setHeightAuto();
+		}
+
+		resetGridItems(child);
+	}
+
+	if (node.style.display === 'grid' && !node.style.height) {
+		node.yogaNode!.setHeightAuto();
+	}
+};
+
+const isOccupied = (occupied: Set<string>, placement: Placement): boolean => {
+	for (let row = placement.row; row < placement.rowEnd; row++) {
+		for (let column = placement.column; column < placement.columnEnd; column++) {
+			if (occupied.has(`${row}:${column}`)) {
+				return true;
+			}
+		}
+	}
+
+	return false;
+};
+
+const occupy = (occupied: Set<string>, placement: Placement): void => {
+	for (let row = placement.row; row < placement.rowEnd; row++) {
+		for (let column = placement.column; column < placement.columnEnd; column++) {
+			occupied.add(`${row}:${column}`);
+		}
+	}
+};
+
+const resolvePlacements = (children: DOMElement[], columns: number): Placement[] => {
+	const occupied = new Set<string>();
+	let cursor = 1;
+
+	return children.map(child => {
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		const columnSpan = column ? column[1] - column[0] : 1;
+		const rowSpan = row ? row[1] - row[0] : 1;
+
+		for (let index = cursor; ; index++) {
+			const candidateColumn = column?.[0] ?? ((index - 1) % columns) + 1;
+			const candidateRow = row?.[0] ?? Math.floor((index - 1) / columns) + 1;
+			const placement = {
+				column: candidateColumn,
+				columnEnd: candidateColumn + columnSpan,
+				row: candidateRow,
+				rowEnd: candidateRow + rowSpan,
+			};
+
+			if (placement.columnEnd - 1 <= columns && !isOccupied(occupied, placement)) {
+				occupy(occupied, placement);
+				cursor = index + 1;
+				return placement;
+			}
+		}
+	});
+};
+
+const resolveTrackSizes = (tracks: Track[], available: number, gap: number, intrinsic: number[]): number[] => {
+	const baseSizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.size;
+		if (track.type === 'auto') return intrinsic[index] ?? 0;
+		if (track.type === 'minmax') return track.max === 'fr' ? track.min : track.max;
+		return 0;
+	});
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - baseSizes.reduce((sum, size) => sum + size, 0));
+	const totalWeight = tracks.reduce((sum, track) => sum + (track.type === 'fr' || (track.type === 'minmax' && track.max === 'fr') ? track.weight : 0), 0);
+
+	return tracks.map((track, index) =>
+		track.type === 'fr' || (track.type === 'minmax' && track.max === 'fr')
+			? baseSizes[index] + (totalWeight === 0 ? 0 : (remaining * track.weight) / totalWeight)
+			: baseSizes[index],
+	);
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	for (const child of gridChildren(node)) {
+		layoutGrid(child);
+	}
+
+	if (node.style.display !== 'grid') {
+		return;
+	}
+
+	const children = gridChildren(node);
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	const columnTracks = columns.length > 0 ? columns : [{type: 'auto'} satisfies Track];
+	const placements = resolvePlacements(children, columnTracks.length);
+	const rowCount = Math.max(1, ...placements.map(placement => placement.rowEnd - 1));
+	const suppliedRows = parseTracks(node.style.gridTemplateRows);
+	const rowTracks = [...suppliedRows];
+	while (rowTracks.length < rowCount) rowTracks.push({type: 'auto'});
+
+	const columnIntrinsic = columnTracks.map(() => 0);
+	const rowIntrinsic = rowTracks.map(() => 0);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		if (placement.columnEnd - placement.column === 1) columnIntrinsic[placement.column - 1] = Math.max(columnIntrinsic[placement.column - 1], child.yogaNode!.getComputedWidth());
+		if (placement.rowEnd - placement.row === 1) rowIntrinsic[placement.row - 1] = Math.max(rowIntrinsic[placement.row - 1], child.yogaNode!.getComputedHeight());
+	}
+
+	const yogaNode = node.yogaNode!;
+	const contentWidth = yogaNode.getComputedWidth() - yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const contentHeight = yogaNode.getComputedHeight() - yogaNode.getComputedPadding(Yoga.EDGE_TOP) - yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - yogaNode.getComputedBorder(Yoga.EDGE_TOP) - yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnGap = getGap(node, Yoga.GUTTER_COLUMN);
+	const rowGap = getGap(node, Yoga.GUTTER_ROW);
+	const columnSizes = resolveTrackSizes(columnTracks, contentWidth, columnGap, columnIntrinsic);
+	const rowSizes = resolveTrackSizes(rowTracks, contentHeight, rowGap, rowIntrinsic);
+
+	if (!node.style.height) yogaNode.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, rowSizes.length - 1) + yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+
+	const columnOffsets = columnSizes.reduce<number[]>((offsets, size) => [...offsets, (offsets.at(-1) ?? 0) + size + columnGap], [0]);
+	const rowOffsets = rowSizes.reduce<number[]>((offsets, size) => [...offsets, (offsets.at(-1) ?? 0) + size + rowGap], [0]);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		const width = columnSizes.slice(placement.column - 1, placement.columnEnd - 1).reduce((sum, size) => sum + size, 0) + columnGap * (placement.columnEnd - placement.column - 1);
+		const height = rowSizes.slice(placement.row - 1, placement.rowEnd - 1).reduce((sum, size) => sum + size, 0) + rowGap * (placement.rowEnd - placement.row - 1);
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column - 1]);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row - 1]);
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height);
+	}
+};
+
+export const applyGridLayout = (root: DOMElement): void => {
+	resetGridItems(root);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	layoutGrid(root);
+};
